def _iceberg_namespace_to_nested(iceberg_namespace: IcebergNamespace) -> IcebergNamespaceNested:
    """Convert flat IcebergNamespace to nested format."""
    attrs = IcebergNamespaceAttributes()
    _populate_iceberg_namespace_attrs(attrs, iceberg_namespace)
    # Categorize relationships by save semantic (REPLACE, APPEND, REMOVE)
    replace_rels, append_rels, remove_rels = categorize_relationships(
        iceberg_namespace, _ICEBERG_NAMESPACE_REL_FIELDS, IcebergNamespaceRelationshipAttributes
    )
    return IcebergNamespaceNested(
        guid=iceberg_namespace.guid,
        type_name=iceberg_namespace.type_name,
        status=iceberg_namespace.status,
        version=iceberg_namespace.version,
        create_time=iceberg_namespace.create_time,
        update_time=iceberg_namespace.update_time,
        created_by=iceberg_namespace.created_by,
        updated_by=iceberg_namespace.updated_by,
        classifications=iceberg_namespace.classifications,
        classification_names=iceberg_namespace.classification_names,
        meanings=iceberg_namespace.meanings,
        labels=iceberg_namespace.labels,
        business_attributes=iceberg_namespace.business_attributes,
        custom_attributes=iceberg_namespace.custom_attributes,
        pending_tasks=iceberg_namespace.pending_tasks,
        proxy=iceberg_namespace.proxy,
        is_incomplete=iceberg_namespace.is_incomplete,
        provenance_type=iceberg_namespace.provenance_type,
        home_id=iceberg_namespace.home_id,
        attributes=attrs,
        relationship_attributes=replace_rels,
        append_relationship_attributes=append_rels,
        remove_relationship_attributes=remove_rels,
    )

def _iceberg_namespace_from_nested(nested: IcebergNamespaceNested) -> IcebergNamespace:
    """Convert nested format to flat IcebergNamespace."""
    attrs = nested.attributes if nested.attributes is not UNSET else IcebergNamespaceAttributes()
    # Merge relationships from all three buckets
    merged_rels = merge_relationships(
        nested.relationship_attributes,
        nested.append_relationship_attributes,
        nested.remove_relationship_attributes,
        _ICEBERG_NAMESPACE_REL_FIELDS,
        IcebergNamespaceRelationshipAttributes
    )
    return IcebergNamespace(
        guid=nested.guid,
        type_name=nested.type_name,
        status=nested.status,
        version=nested.version,
        create_time=nested.create_time,
        update_time=nested.update_time,
        created_by=nested.created_by,
        updated_by=nested.updated_by,
        classifications=nested.classifications,
        classification_names=nested.classification_names,
        meanings=nested.meanings,
        labels=nested.labels,
        business_attributes=nested.business_attributes,
        custom_attributes=nested.custom_attributes,
        pending_tasks=nested.pending_tasks,
        proxy=nested.proxy,
        is_incomplete=nested.is_incomplete,
        provenance_type=nested.provenance_type,
        home_id=nested.home_id,
        **_extract_iceberg_namespace_attrs(attrs),
        # Merged relationship attributes
        **merged_rels,
    )

def _iceberg_namespace_to_nested_bytes(iceberg_namespace: IcebergNamespace, serde: Serde) -> bytes:
    """Convert flat IcebergNamespace to nested JSON bytes."""
    return serde.encode(_iceberg_namespace_to_nested(iceberg_namespace))


def _iceberg_namespace_from_nested_bytes(data: bytes, serde: Serde) -> IcebergNamespace:
    """Convert nested JSON bytes to flat IcebergNamespace."""
    nested = serde.decode(data, IcebergNamespaceNested)
    return _iceberg_namespace_from_nested(nested)

